import java.io.IOException;

public class CommandInjectionDemo {

    public static void main(String[] args) throws IOException {
        // Simulating user input being passed as a command argument
        String userInput = "example.txt; ls";

        // Validate and sanitize user input to prevent command injection
        if (!isValidInput(userInput)) {
            System.out.println("Invalid input. Aborting.");
            return;
        }

        // Safe code where user input is properly handled to prevent command injection
        String command = "cat " + userInput;

        Process process = Runtime.getRuntime().exec(command);
    }

    private static boolean isValidInput(String userInput) {
        // Add your validation logic here based on acceptable input patterns or whitelist
        // Example: Check if userInput contains only alphanumeric characters and specific allowed symbols
        return userInput.matches("^[a-zA-Z0-9_.-]*$");
    }
